var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헥… 헥… 살았다.","JPN":"ぜえ……ぜえ……助かった。","ENG":"*Huff...* *Huff...* I'm alive.","TWN":"呼……呼……得救了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"고마워요, 선장님.","JPN":"ありがとうございます、船長。","ENG":"Thanks, Captain.","TWN":"謝謝你，船長。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"혼자 다 먹으려다가 벌받은 거라고, 탈리.","JPN":"独り占めしようとするから罰が当たったんだよ、タリー。","ENG":"That's what you get for trying to hog everything yourself, Tallie.","TWN":"這都是因為妳想獨吞而受到的懲罰，塔莉。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아, 아무튼 관리국 요청대로 침식체들을 처리했으니까 된 거 아닐까요오…….","JPN":"と、とにかく管理局の要請どおりに侵食体を処理したからいいじゃないですかぁ……","ENG":"W-well, we handled the C.O.s just like the Administration asked, so isn't that good enough...?","TWN":"啊，總之按照管理局的要求處理侵蝕體不就好了嗎……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"하아, 상황이 꽤 심각하네요.","JPN":"はあ、状況はかなり厳しいと見受けられます。","ENG":"*Sigh* The situation is pretty serious.","TWN":"唉，情況很嚴重呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이 바다에서 나오지 않았던 침식체들이 이렇게 튀어나올 줄이야.","JPN":"フロントベイの海では出没していなかった侵食体がこんなに出てくるなんて。","ENG":"C.O.s that never left the Front Bay waters are spilling out like this.","TWN":"沒想到前灣海域會出現這麼多侵蝕體。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"아무래도 대균열의 이상 현상이 예측보다 훨씬 더 심각한 수준인 것 같네요.","JPN":"どうやら大亀裂の異常現象は、予想よりずっと深刻なレベルのようですね。","ENG":"The anomalies in the Grand Dimension Crevice must be far worse than predicted.","TWN":"看來大峽谷的異常現象比預測的還更嚴重。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그나저나, 이 사람은 누구죠?","JPN":"ところで、この人は誰ですか？","ENG":"Anyway, who is this?","TWN":"話說這個人是誰？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"신참을 받는다는 말은 못 들었는데…….","JPN":"新入りが入るとは聞いていませんでしたが……","ENG":"I didn't hear anything about taking in a new crew mate...","TWN":"我沒聽說要收新手……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 관리국 죄수야. 5년 전에 일어났던 프론트 베이 선상 반란, 기억나?","JPN":"あ、管理局の囚人さ。5年前のフロントベイ船上反乱、覚えてるか？","ENG":"Oh, she's an Administration prisoner. Remember the Front Bay Shipboard Rebellion five years ago?","TWN":"啊，她是管理局的囚犯。妳還記得5年前的前灣船上叛亂嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"완전 짜릿했죠.","JPN":"すごく刺激的でしたよね。","ENG":"That was totally electrifying.","TWN":"那超刺激的啊。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그 혼돈을 틈타 저도 건물 몇 채 정도는 부숴 먹었거든요.","JPN":"その混沌に乗じて、私も建物を何軒か壊しましたし。","ENG":"I smashed a few buildings myself in the chaos.","TWN":"我也趁亂砸了幾棟建築。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그때 느꼈던 그 황홀감이란……!","JPN":"あの時感じた甘美な気分といったら……！","ENG":"Ahh, the thrill of that moment...!","TWN":"那種快感……！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흠, 흠! 아무튼 그때 주동자가 바로 이 사람이란 말씀.","JPN":"ゴホン、ゴホン。とにかく、あの時の首謀者がこの人ってこと。","ENG":"Ahem! Anyway, the ringleader back then was this person.","TWN":"嗯，嗯！總之，當年的主謀就是這位小姐。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아, 예비 해적 후보생이군요!","JPN":"まあ、予備海賊候補生なんですね！","ENG":"Ah, so she's an aspiring pirate!","TWN":"啊，是準海盜候補生啊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"반가워요, 저는 탈리 크루, 해적이죠!","JPN":"はじめまして。私はタリー・クルー、海賊です！","ENG":"Nice to meet you! I'm Tallie Crew, a pirate!","TWN":"很高興認識妳。我是塔莉·克盧，是個海盜！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그, 그래. 반가워.","JPN":"あ、ああ。はじめまして。","ENG":"Y-yeah. Nice to meet you.","TWN":"嗯、嗯，請多指教。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"넌 왜 해적이 된 거야?","JPN":"お前はどうして海賊になったんだ？","ENG":"Why did you become a pirate?","TWN":"妳為什麼會成為海盜？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"아주 철학적인 질문을 좋아하시는 분이군요!","JPN":"哲学的な質問がお好きな方なんですね！","ENG":"You're someone who likes deep, philosophical questions!","TWN":"原來是個喜歡哲學問題的人啊！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저는 그저 펑펑 터뜨리는 게 좋아서 해적이 됐어요!","JPN":"私はただドカンドカン爆発させるのが好きで海賊になりました！","ENG":"I became a pirate simply because I love blowing things up!","TWN":"我喜歡爆破東西，所以成為海盜！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L40_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"범죄자가 된다면 폭탄을 터뜨려도 상관없어지는 거잖아요?","JPN":"犯罪者になれば、爆弾を爆発させても問題ないですもんね？","ENG":"If I'm a criminal, then nobody can complain about me detonating bombs!","TWN":"當個罪犯，就算引爆炸彈也沒關係啊？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG"},{"id":"L43_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"쟤는 생각하는 게 우리랑 달라.","JPN":"あの子はあたしたちとは思考回路が違うから。","ENG":"She thinks differently from the rest of us.","TWN":"她的想法和我們不一樣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그냥 그렇구나 넘어가면 돼.","JPN":"そうですかって聞き流して。","ENG":"Just let it go.","TWN":"就這樣吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"전 그저 자유와 폭발을 사랑하는 해적일 뿐이라고요!","JPN":"私は自由と爆発を愛する海賊なだけです！","ENG":"I'm just a pirate who loves freedom and explosions!","TWN":"我只是喜歡自由和爆炸的海盜而已！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그러는 소냐도 회라면 사족을 못쓰는 바람에 크라켄도 먹어봤으면서!","JPN":"そういうソーニャだって、刺身には目がなくて、クラーケンまで食べたんですよ！","ENG":"And you, Sonya. You went crazy over sashimi and even ate Kraken!","TWN":"可是索妮雅吃生魚片吃到走不動，連克拉肯都吃過！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"한 입만 먹고 뱉었잖아.","JPN":"一口だけ食べてすぐ吐いたし。","ENG":"I only took one bite and spat it out.","TWN":"我只咬一口就吐掉啦。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"생각보다 도시 상황이 훨씬 위험한 것 같은데…….","JPN":"都市の状況は想像以上に危ないようですね……","ENG":"The city's in worse danger than I thought...","TWN":"看來城市的情況比想像的更危險……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통.","JPN":"おい、ポンコツ。","ENG":"Hey, tin can.","TWN":"喂，鐵桶。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이쪽 섹터는 얼추 정리가 된 것 같은데… 얼른 다음으로 넘어가지?","JPN":"こっちのセクターはだいたい片付いたみたいだから……さっさと次に行こうぜ。","ENG":"Looks like this sector is mostly cleaned up... let's move on to the next one.","TWN":"這區似乎差不多整理完了……快去下一區吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"지금 그런 걸 걱정할 때예요?","JPN":"今それどころではありません。","ENG":"Is that really what you should be worrying about right now?","TWN":"現在是擔心這個的時候嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"도시가 위험하다고요, 도시가.","JPN":"都市が危ないのですよ、都市が。","ENG":"The city is in danger. The city.","TWN":"城市很危險啊，城市！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"육지에서나 목격할 수 있었던 침식체들이 바다까지 장악했어요.","JPN":"陸地でしか目撃されなかった侵食体が、海に来て、そこを掌握しているんです。","ENG":"C.O.s that were only ever seen on land have taken over the sea.","TWN":"陸地上才會看到的侵蝕體，現在連大海都掌控了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄이 막을 수 없을 정도로 대균열이 넓어졌다는 소린데…….","JPN":"クラーケンでは塞ぎ切れないほどに大亀裂が開いてしまったという意味ですが……","ENG":"That means the Grand Dimension Crevice has widened beyond what Kraken can hold back...","TWN":"大峽谷已經擴張到連克拉肯都無法阻擋的程度了……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그러고보니… 안개가 좀 많아진 것 같기도 하고…….","JPN":"そういえば……霧がひどくなったような気もするな……","ENG":"Come to think of it... the fog does look thicker...","TWN":"這麼說來……霧好像變得更濃了……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"바다에 끼는 안개는 크라켄이 영역을 넓히기 위해 내뿜는 거예요.","JPN":"海の霧はクラーケンが縄張りを広げるために吐き出しているのです。","ENG":"That fog on the sea is what Kraken releases to expand its territory.","TWN":"海上會起霧，是因為克拉肯為了擴大自己的領域而吐出的霧氣。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그게 이 앞바다까지 왔다는 것은… 크라켄이 격벽 코앞까지 왔다는 소리죠.","JPN":"それがこの近海まで来たということは……クラーケンが隔壁のすぐ前まで来ているということなんです。","ENG":"If it's drifted all the way out here... it means Kraken is right up against the bulwark.","TWN":"而霧都飄到前海這裡，代表……克拉肯已經逼近屏障了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그렇다면 관리국 병력을 운용해서…….","JPN":"ならば管理局の兵力を使って……","ENG":"If that's the case, we should deploy the Administration forces–","TWN":"那麼就該動用管理局的兵力……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"벨라미. 프론트 베이 주변 섬으로부터 긴급한 지원 요청이 들어왔다.","JPN":"ベラミー。フロントベイ周辺にある島から緊急支援要請が入った。","ENG":"Bellamy. We just got an emergency request from one of the islands near Front Bay.","TWN":"貝拉米，收到前灣附近的島嶼發來的緊急支援請求。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이곳에서 2시간 정도 떨어진 섬으로… 발신자는…….","JPN":"ここから2時間ほど離れている島で……発信者は……","ENG":"It's from an island about two hours out... the sender is...","TWN":"距離這裡大概約2小時的島嶼……發信者是……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스라고 하는군.","JPN":"フローラメイドサービス、とういうらしい。","ENG":"Flora Maid Service, apparently.","TWN":"芙蘿拉女僕服務。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"요즘은 메이드도 침식체와 전투를 하나?","JPN":"最近はメイドも侵食体と戦うのか？","ENG":"Do maids fight C.O.s these days?","TWN":"最近連女僕都會和侵蝕體戰鬥了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};